// // This comment suggests that the decoder outputs a single bit high for each input, but it actually produces a 16-bit vector with only one bit set.
module decoder_4to16 (
    input [3:0] in,
    output reg [15:0] out
);
    always @(*) begin
        out = 16'b0000_0000_0000_0000; // Default to all zeros
        out[in] = 1'b1; // Set the output corresponding to the input
    end
endmodule
